arguments.command:
# Check if the addresses 0x2f4b20 and 0x2f4c84 fall in any DWARF address range
python3 << 'EOF'
import subprocess

# Get aranges to find compilation units covering these addresses
result = subprocess.run(
    ['aarch64-linux-gnu-readelf', '--debug-dump=aranges', '/tmp/symbols/libmonosgen-2.0.so.debug'],
    capture_output=True, text=True
)

targets = [0x2f4b20, 0x2f4c84]
current_cu = None
for line in result.stdout.split('\n'):
    if 'CU:' in line:
        current_cu = line.strip()
    elif '0x' in line and not line.strip().startswith('Length') and not line.strip().startswith('Version'):
        parts = line.strip().split()
        if len(parts) >= 2:
            try:
                start = int(parts[0], 16)
                length = int(parts[1], 16)
                end = start + length
                for t in targets:
                    if start <= t < end:
                        print(f"  0x{t:x} found in range 0x{start:x}-0x{end:x} (len {length}), {current_cu}")
            except ValueError:
                pass

# Also let's look at what's between the last known symbol and our addresses
# Use nm to get all symbols sorted numerically from the debug file
result2 = subprocess.run(
    ['aarch64-linux-gnu-nm', '-n', '-S', '/tmp/symbols/libmonosgen-2.0.so.debug'],
    capture_output=True, text=True
)

# Find functions near our target addresses
for target in [0x2f4b20, 0x2f4c84]:
    best = None
    for line in result2.stdout.split('\n'):
        parts = line.split()
        if len(parts) >= 3:
            try:
                addr = int(parts[0], 16)
                if addr <= target:
                    if len(parts) >= 4:
                        best = (addr, int(parts[1], 16), parts[3])
                    else:
                        best = (addr, 0, parts[2])
            except ValueError:
                pass
    if best:
        print(f"0x{target:x}: nearest symbol = {best[2]} at 0x{best[0]:x} (size 0x{best[1]:x}), offset +0x{target-best[0]:x}")
EOF

